using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=5e5+5;
int n,a[MAXN],dep[MAXN],f[MAXN][26],m,b,d[MAXN],sum[MAXN],o,p;
vector<int> g[MAXN]; 
void dfs(int u,int fa)
{
	dep[u]=dep[fa]+1;
	f[u][0]=fa;
	FOR(i,1,25)
	{
		f[u][i]=f[f[u][i-1]][i-1];
	}
	FOI(s,g[u])
	{
		if(s==fa)continue;
		dfs(s,u);
	}
} 
int LCA(int x,int y)
{
	if(dep[y]>dep[x])swap(x,y);

	ROF(i,25,0)
	{
		if(dep[f[x][i]]>=dep[y])
		{
			x=f[x][i];
		}
	}
	if(x==y)
	{
		return x;
	}
	ROF(i,25,0)
	{
		if(f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
void dfs2(int u,int fa)
{
	FOI(s,g[u])
	{
		if(s==fa)continue;
		dfs2(s,u);
		d[u]+=d[s];
	}
}
